#!/bin/bash

# Check if a logfile parameter is provided
if [ -z "$1" ]; then
  echo "Usage: $0 <logfile>"
  exit 1
fi

LOGFILE="$1"
ARCHIVE_DIR="/archive"

# Create the archive directory if it doesn't exist
mkdir -p "$ARCHIVE_DIR"

# Copy the logfile to the archive directory
cp "/var/log/$LOGFILE" "$ARCHIVE_DIR/"

# Check if the copy was successful
if [ $? -eq 0 ]; then
  echo "Logfile $LOGFILE has been archived to $ARCHIVE_DIR."
else
  echo "Failed to archive logfile $LOGFILE."
  exit 1
fi